# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import os
import functions_framework
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime


# Configuration - set these via environment variables or directly
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", "your-project-id")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-topic")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def get_storage_client():
    """Create a Cloud Storage client."""
    return storage.Client(project=PROJECT_ID)


def get_firestore_client():
    """Create a Firestore client."""
    return firestore.Client(project=PROJECT_ID)


def get_pubsub_publisher():
    """Create a Pub/Sub publisher client."""
    return pubsub_v1.PublisherClient()


def read_file_from_gcs(bucket_name, file_name):
    """Read a file from Google Cloud Storage."""
    client = get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(
            f"File {file_name} not found in bucket {bucket_name}"
        )

    content = blob.download_as_text()
    metadata = {
        "name": blob.name,
        "bucket": blob.bucket.name,
        "size": blob.size,
        "content_type": blob.content_type,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
    }
    return content, metadata


def process_file_content(content, metadata):
    """
    Process file content - customize this for your MVP needs.
    This example extracts basic stats and parses JSON/CSV content.
    """
    result = {
        "file_name": metadata["name"],
        "bucket": metadata["bucket"],
        "file_size": metadata["size"],
        "content_type": metadata["content_type"],
        "line_count": len(content.splitlines()),
        "char_count": len(content),
        "processed_at": datetime.utcnow().isoformat(),
        "status": "processed",
    }

    # Try to parse as JSON
    if metadata.get("content_type") == "application/json" or metadata[
        "name"
    ].endswith(".json"):
        try:
            parsed_data = json.loads(content)
            if isinstance(parsed_data, list):
                result["record_count"] = len(parsed_data)
                result["data_type"] = "json_array"
            elif isinstance(parsed_data, dict):
                result["record_count"] = 1
                result["data_type"] = "json_object"
                result["keys"] = list(parsed_data.keys())
            result["parse_status"] = "success"
        except json.JSONDecodeError:
            result["parse_status"] = "invalid_json"

    # Try to parse as CSV
    elif metadata["name"].endswith(".csv"):
        lines = content.splitlines()
        if lines:
            result["data_type"] = "csv"
            result["header"] = lines[0].split(",")
            result["record_count"] = len(lines) - 1  # exclude header
            result["column_count"] = len(result["header"])
            result["parse_status"] = "success"

    else:
        result["data_type"] = "text"
        result["parse_status"] = "raw_text"

    return result


def write_to_firestore(document_data, document_id=None):
    """Write processing results to Firestore."""
    client = get_firestore_client()
    collection_ref = client.collection(FIRESTORE_COLLECTION)

    if document_id:
        doc_ref = collection_ref.document(document_id)
        doc_ref.set(document_data)
    else:
        doc_ref = collection_ref.add(document_data)
        document_id = doc_ref[1].id

    print(f"Written to Firestore: {FIRESTORE_COLLECTION}/{document_id}")
    return document_id


def publish_to_pubsub(message_data):
    """Publish processing notification to Pub/Sub."""
    publisher = get_pubsub_publisher()
    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    # Pub/Sub messages must be bytes
    message_bytes = json.dumps(message_data, default=str).encode("utf-8")

    # Add attributes for filtering
    attributes = {
        "source": "file-processor",
        "status": message_data.get("status", "unknown"),
        "file_type": message_data.get("data_type", "unknown"),
    }

    future = publisher.publish(topic_path, data=message_bytes, **attributes)
    message_id = future.result()

    print(f"Published message {message_id} to {topic_path}")
    return message_id


@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    Processes the uploaded file, writes results to Firestore,
    and publishes a notification to Pub/Sub.

    Trigger: google.cloud.storage.object.v1.finalized
    """
    data = cloud_event.data

    bucket_name = data["bucket"]
    file_name = data["name"]

    print(f"Processing file: gs://{bucket_name}/{file_name}")

    try:
        # Step 1: Read file from Cloud Storage
        content, metadata = read_file_from_gcs(bucket_name, file_name)
        print(f"Read file: {metadata['name']} ({metadata['size']} bytes)")

        # Step 2: Process the file content
        processing_result = process_file_content(content, metadata)
        print(f"Processing result: {processing_result['status']}")

        # Step 3: Write results to Firestore
        # Use a sanitized file name as the document ID
        doc_id = file_name.replace("/", "_").replace(".", "_")
        firestore_doc_id = write_to_firestore(processing_result, doc_id)
        processing_result["firestore_document_id"] = firestore_doc_id

        # Step 4: Publish notification to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed",
            "file_name": file_name,
            "bucket": bucket_name,
            "firestore_document_id": firestore_doc_id,
            "firestore_collection": FIRESTORE_COLLECTION,
            "status": processing_result["status"],
            "data_type": processing_result.get("data_type"),
            "record_count": processing_result.get("record_count"),
            "processed_at": processing_result["processed_at"],
        }
        message_id = publish_to_pubsub(pubsub_message)
        print(f"Pipeline complete. Pub/Sub message ID: {message_id}")

        return {"status": "success", "message_id": message_id}

    except FileNotFoundError as e:
        error_result = {
            "file_name": file_name,
            "bucket": bucket_name,
            "status": "error",
            "error": str(e),
            "processed_at": datetime.utcnow().isoformat(),
        }
        write_to_firestore(error_result)
        publish_to_pubsub(
            {"event_type": "file_processing_error", "error": str(e)}
        )
        print(f"Error: {e}")
        raise

    except Exception as e:
        error_result = {
            "file_name": file_name,
            "bucket": bucket_name,
            "status": "error",
            "error": str(e),
            "error_type": type(e).__name__,
            "processed_at": datetime.utcnow().isoformat(),
        }
        # Attempt to log the error to Firestore
        try:
            write_to_firestore(error_result)
        except Exception as firestore_err:
            print(f"Failed to write error to Firestore: {firestore_err}")

        # Attempt to publish error notification
        try:
            publish_to_pubsub(
                {
                    "event_type": "file_processing_error",
                    "file_name": file_name,
                    "bucket": bucket_name,
                    "error": str(e),
                }
            )
        except Exception as pubsub_err:
            print(f"Failed to publish error to Pub/Sub: {pubsub_err}")

        print(f"Error processing file: {e}")
        raise


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered version for testing and manual invocations.
    Expects JSON body: {"bucket": "my-bucket", "file_name": "path/to/file.json"}
    """
    request_json = request.get_json(silent=True)

    if not request_json:
        return json.dumps({"error": "Request body must be JSON"}), 400

    bucket_name = request_json.get("bucket")
    file_name = request_json.get("file_name")

    if not bucket_name or not file_name:
        return (
            json.dumps(
                {"error": "Both 'bucket' and 'file_name' are required"}
            ),
            400,
        )

    print(f"HTTP trigger: Processing file gs://{bucket_name}/{file_name}")

    try:
        # Step 1: Read file from Cloud Storage
        content, metadata = read_file_from_gcs(bucket_name, file_name)

        # Step 2: Process the file content
        processing_result = process_file_content(content, metadata)

        # Step 3: Write results to Firestore
        doc_id = file_name.replace("/", "_").replace(".", "_")
        firestore_doc_id = write_to_firestore(processing_result, doc_id)
        processing_result["firestore_document_id"] = firestore_doc_id

        # Step 4: Publish notification to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed",
            "file_name": file_name,
            "bucket": bucket_name,
            "firestore_document_id": firestore_doc_id,
            "firestore_collection": FIRESTORE_COLLECTION,
            "status": processing_result["status"],
            "data_type": processing_result.get("data_type"),
            "record_count": processing_result.get("record_count"),
            "processed_at": processing_result["processed_at"],
            "trigger": "http",
        }
        message_id = publish_to_pubsub(pubsub_message)

        response = {
            "status": "success",
            "processing_result": processing_result,
            "pubsub_message_id": message_id,
        }
        return json.dumps(response, default=str), 200

    except FileNotFoundError as e:
        return json.dumps({"error": str(e)}), 404
    except Exception as e:
        return (
            json.dumps({"error": str(e), "error_type": type(e).__name__}),
            500,
        )


# --- DEPLOYMENT SCRIPT (run separately, not part of the Cloud Function) ---
def generate_deployment_script():
    """
    Generates the shell commands needed to deploy this function.

    WARNING: This setup uses broad permissions for rapid MVP development.
    For production, follow the principle of least privilege:
    - Use storage.objectViewer instead of storage.admin
    - Use datastore.user scoped to specific collections
    - Use pubsub.publisher scoped to specific topics
    - Consider using Workload Identity Federation
    """
    script = """#!/bin/bash
# ==============================================================================
# DEPLOYMENT SCRIPT FOR FILE PROCESSING CLOUD FUNCTION
#
# SECURITY WARNING: This configuration uses broad permissions for rapid MVP
# development. Before moving to production, you MUST:
#   1. Replace broad roles with fine-grained, least-privilege permissions
#   2. Scope permissions to specific resources (buckets, topics, collections)
#   3. Enable audit logging
#   4. Review and rotate service account keys
#   5. Use VPC Service Controls if handling sensitive data
# ==============================================================================

set -euo pipefail

# Configuration
PROJECT_ID="your-project-id"
REGION="us-central1"
FUNCTION_NAME="file-processor"
SERVICE_ACCOUNT_NAME="file-processor-sa"
TRIGGER_BUCKET="your-trigger-bucket"
PUBSUB_TOPIC="file-processing-topic"
FIRESTORE_COLLECTION="processed_files"

echo "=== Setting up GCP project ==="
gcloud config set project ${PROJECT_ID}

# Enable required APIs
echo "=== Enabling APIs ==="
gcloud services enable \
    cloudfunctions.googleapis.com \
    cloudbuild.googleapis.com \
    storage.googleapis.com \
    firestore.googleapis.com \
    pubsub.googleapis.com \
    run.googleapis.com \
    eventarc.googleapis.com

# Create service account
echo "=== Creating service account ==="
gcloud iam service-accounts create ${SERVICE_ACCOUNT_NAME} \
    --display-name="File Processor Cloud Function SA" \
    --description="Service account for file processing Cloud Function (MVP - broad permissions)" \
    || echo "Service account already exists"

SA_EMAIL="${SERVICE_ACCOUNT_NAME}@${PROJECT_ID}.iam.gserviceaccount.com"

# Assign roles to the service account
# WARNING: These are broad permissions for MVP development.
# For production, use least-privilege principle:
#   - roles/storage.objectViewer instead of roles/storage.admin
#   - Custom role with only firestore.documents.{get,create,update} instead of roles/datastore.user
#   - roles/pubsub.publisher scoped to specific topic instead of project-wide
echo "=== Assigning IAM roles (MVP - broad permissions) ==="

# Storage Admin - allows read/write/delete on all buckets
# PRODUCTION: Use roles/storage.objectViewer on specific bucket
gcloud projects add-iam-policy-binding ${PROJECT_ID} \
    --member="serviceAccount:${SA_EMAIL}" \
    --role="roles/storage.admin" \
    --condition=None

# Datastore User - allows read/write on all Firestore collections
# PRODUCTION: Use Firestore Security Rules + custom role with minimal permissions
gcloud projects add-iam-policy-binding ${PROJECT_ID} \
    --member="serviceAccount:${SA_EMAIL}" \
    --role="roles/datastore.user" \
    --condition=None

# Pub/Sub Publisher - allows publishing to all topics
# PRODUCTION: Use IAM condition to restrict to specific topic
gcloud projects add-iam-policy-binding ${PROJECT_ID} \
    --member="serviceAccount:${SA_EMAIL}" \
    --role="roles/pubsub.publisher" \
    --condition=None

# Create Pub/Sub topic
echo "=== Creating Pub/Sub topic ==="
gcloud pubsub topics create ${PUBSUB_TOPIC} || echo "Topic already exists"

# Create a subscription for testing
gcloud pubsub subscriptions create ${PUBSUB_TOPIC}-sub \
    --topic=${PUBSUB_TOPIC} \
    || echo "Subscription already exists"

# Create trigger bucket if it doesn't exist
echo "=== Creating trigger bucket ==="
gsutil mb -p ${PROJECT_ID} -l ${REGION} gs://${TRIGGER_BUCKET} \
    || echo "Bucket already exists"

# Grant Eventarc permissions for GCS triggers
echo "=== Setting up Eventarc permissions ==="
PROJECT_NUMBER=$(gcloud projects describe ${PROJECT_ID} --format='value(projectNumber)')
GCS_SA="service-${PROJECT_NUMBER}@gs-project-accounts.iam.gserviceaccount.com"

gcloud projects add-iam-policy-binding ${PROJECT_ID} \
    --member="serviceAccount:${GCS_SA}" \
    --role="roles/pubsub.publisher" \
    --condition=None

# Deploy the Cloud Function (GCS trigger)
echo "=== Deploying Cloud Function (GCS trigger) ==="
gcloud functions deploy ${FUNCTION_NAME} \
    --gen2 \
    --runtime=python312 \
    --region=${REGION} \
    --source=. \
    --entry-point=process_gcs_file \
    --trigger-event-filters="type=google.cloud.storage.object.v1.finalized" \
    --trigger-event-filters="bucket=${TRIGGER_BUCKET}" \
    --service-account=${SA_EMAIL} \
    --set-env-vars="GCP_PROJECT_ID=${PROJECT_ID},PUBSUB_TOPIC=${PUBSUB_TOPIC},FIRESTORE_COLLECTION=${FIRESTORE_COLLECTION}" \
    --memory=256Mi \
    --timeout=120s \
    --max-instances=10

# Deploy HTTP version for testing
echo "=== Deploying Cloud Function (HTTP trigger) ==="
gcloud functions deploy ${FUNCTION_NAME}-http \
    --gen2 \
    --runtime=python312 \
    --region=${REGION} \
    --source=. \
    --entry-point=process_file_http \
    --trigger-http \
    --allow-unauthenticated \
    --service-account=${SA_EMAIL} \
    --set-env-vars="GCP_PROJECT_ID=${PROJECT_ID},PUBSUB_TOPIC=${PUBSUB_TOPIC},FIRESTORE_COLLECTION=${FIRESTORE_COLLECTION}" \
    --memory=256Mi \
    --timeout=120s \
    --max-instances=10

echo ""
echo "=== Deployment Complete ==="
echo "GCS Trigger Function: ${FUNCTION_NAME}"
echo "HTTP Function URL: $(gcloud functions describe ${FUNCTION_NAME}-http --gen2 --region=${REGION} --format='value(serviceConfig.uri)')"
echo ""
echo "=== Test Commands ==="
echo "# Upload a file to trigger processing:"
echo "echo '{\"hello\": \"world\"}' | gsutil cp - gs://${TRIGGER_BUCKET}/test.json"
echo ""
echo "# Or use HTTP endpoint:"
echo "curl -X POST $(gcloud functions describe ${FUNCTION_NAME}-http --gen2 --region=${REGION} --format='value(serviceConfig.uri)') \\\\"
echo "  -H 'Content-Type: application/json' \\\\"
echo "  -d '{\"bucket\": \"${TRIGGER_BUCKET}\", \"file_name\": \"test.json\"}'"
echo ""
echo "# Check Pub/Sub messages:"
echo "gcloud pubsub subscriptions pull ${PUBSUB_TOPIC}-sub --auto-ack --limit=10"
echo ""
echo "=============================================="
echo "SECURITY REMINDER FOR PRODUCTION:"
echo "  1. Replace roles/storage.admin with roles/storage.objectViewer"
echo "  2. Scope Firestore access to specific collections"
echo "  3. Restrict Pub/Sub publisher to specific topics"
echo "  4. Remove --allow-unauthenticated from HTTP function"
echo "  5. Add VPC connector for network isolation"
echo "=============================================="
"""
    return script


